13	func expireContractsRunner(store Storage, eventProducer Producer) func(ctx context.Context) {
14		return func(ctx context.Context) {
15			contracts, err := store.FindAndUpdateExpiredContracts(ctx)
16			if err != nil {
17				// The function above returns any successful contracts before an error occurred
18				tlog.WithError(err).
19					WithAttribute("successful_count", fmt.Sprintf("%d", len(contracts))).
20					Error(ctx, "failed to find and update expired contracts")
21			}
22	
23			for _, contract := range contracts {
24				var expiresAt *timestamppb.Timestamp
25				if contract.ExpiresAt != nil {
26					expiresAt = timestamppb.New(*contract.ExpiresAt)
27				}
28	
29				if err := eventProducer.ProduceMobileHandsetContractExpiredSync(ctx, &serviceevents.MobileHandsetContractExpired{
30					ServiceId:  contract.ServiceID,
31					CustomerId: contract.CustomerID,
32					ContractId: contract.ID.String(),
33					HandsetId:  contract.HandsetID,
34					ExpiresAt:  expiresAt,
35				}); err != nil {
36					tlog.WithError(err).
37						WithAttribute("contract_id", contract.ID.String()).
38						Error(ctx, "failed to produce MobileHandsetContractExpired event")
39				}
40			}
41		}
42	}
