1	package jobs
2	
3	import (
4		"context"
5		"time"
6	
7		"github.com/utilitywarehouse/telecom-mobile/internal/shared/scheduler"
8		"github.com/utilitywarehouse/telecom-mobile/pkg/generated/protos/mobile/v1/events/serviceevents"
9		"github.com/utilitywarehouse/telecom-mobile/services/handset/internal/models"
10	)
11	
12	//go:generate mockgen -destination=./mocks/$GOFILE -source=./$GOFILE
13	
14	type Storage interface {
15		FindAndUpdateExpiredContracts(ctx context.Context) ([]models.Contract, error)
16	}
17	
18	type Producer interface {
19		ProduceMobileHandsetContractExpiredSync(ctx context.Context, out *serviceevents.MobileHandsetContractExpired) error
20	}
21	
22	type Jobs struct {
23		scheules []*scheduler.Scheduler
24	}
25	
26	func New(ctx context.Context, store Storage, eventProducer Producer) *Jobs {
27		res := &Jobs{
28			scheules: []*scheduler.Scheduler{},
29		}
30	
31		res.scheules = append(res.scheules, scheduler.NewScheduler(ctx, expireContractsRunner(store, eventProducer), time.Hour*6))
32	
33		return res
34	}
35	
36	func (j *Jobs) Start() {
37		for _, job := range j.scheules {
38			job.Start()
39		}
40	}
41	
42	func (j *Jobs) Stop() {
43		for _, job := range j.scheules {
44			job.Stop()
45		}
46	}
